from models.bug_task import BugTask
from models.feature_task import FeatureTask

def parse_task(raw):
    kind, title, detail, status = raw.strip().split("|")
    if kind == "bug":
        return BugTask(title, detail, status)
    return FeatureTask(title, detail, status)

def load_tasks(path):
    return [parse_task(line) for line in open(path) if line.strip()]

def summary_report(tasks):
    lines = ["Task Summary"]
    for task in tasks:
        lines.append(task.label())
    return "\n".join(lines)

